  'POST /api/v2/spacemolt/craft': {
    operationId: 'spacemolt_craft',
    summary: 'Queue a crafting job (auto-routes to your own/faction facility, or hand-crafts at the Station Workshop)',
    stateSections: ['player', 'ship', 'cargo'],
    route: {
      tool: 'spacemolt',
      action: 'craft',
      method: 'POST',
    },
    schema: {
      count: {
        type: 'integer',
        description: 'Alias for quantity (used when quantity is not set).',
      },
      deliver_to: {
        type: 'string',
        description:
          "Output destination: 'storage' (default), 'faction' (faction main store — requires manage treasury permission), or 'faction:<bucket name or id>' for a specific faction Storage Extension bucket.",
      },
      dry_run: {
        type: 'boolean',
        description:
          'Return a cost+time quote (materials, labor, rental fee, auto-routed venue, ETA) without queuing or spending anything. Not supported with bulk jobs.',
      },
      facility_id: {
        type: 'string',
        description: 'Route to a specific facility ID (overrides auto-selection).',
      },
      id: {
        type: 'string',
        description:
          'Recipe ID to craft (use catalog with type=recipes to see available recipes). Inputs are escrowed from station storage at enqueue.',
        positionalIndex: 0,
      },
      items: {
        type: 'array',
        description: 'For pack_package: selected items to pack; total unpacked size may not exceed 100.',
      },
      job_id: {
        type: 'string',
        description:
          "Cancel this queued job (refunding its unconsumed inputs, labor, and rental fee) instead of crafting. Use action='queue' to list your job IDs. Setting job_id implies cancel.",
      },
      job_ids: {
        type: 'array',
        description:
          "Bulk cancel: cancel many queued jobs in one action. Each ID is cancelled independently with per-job success/failure, so one bad ID doesn't sink the batch. Refunds the unconsumed escrow of every cancelled job.",
      },
      jobs: {
        type: 'array',
        description:
          'Bulk mode: queue many crafts in one action. Package entries may include items, package_id, label, and target. Each job commits independently with partial success. Max 50.',
      },
      label: {
        type: 'string',
        description: 'For pack_package: player-authored package label.',
      },
      output_package_label: {
        type: 'string',
        description:
          'Bundle the outputs into one package: instead of depositing outputs loose per run, the job holds them and seals them into a single new package with this label in the destination on completion, consuming one cargo_container. Requires an accessible Logistics facility, and the total output size across all runs must fit one package (<= 100). Cancelling refunds the inputs and produces no package.',
      },
      package_id: {
        type: 'string',
        description: 'For unpack_package: package instance ID to unpack.',
      },
      package_ids: {
        type: 'array',
        description:
          "Source this craft's inputs from these packages (raw id or 'package:<id>' form) instead of loose storage items. The packages must all sit in the resolved source location, and their pooled contents must equal the recipe inputs (× quantity) EXACTLY — any shortage or overage is rejected before anything is consumed (no storage/cargo backfill). Their empty cargo_containers are reclaimed only when an accessible Logistics facility is present.",
      },
      preset: {
        type: 'string',
        enum: ['fast', 'cheap', 'prefer_own', 'workshop'],
        description:
          "Auto-routing preset: 'fast' (fewest ticks, default) picks the best facility globally, so a busy own facility may route to an idle public rental. 'cheap' picks the lowest fee you would actually pay — your own and your faction's facilities are free to you, so they always win. Use 'prefer_own' to keep the job on your own (then faction, then ally-granted) facility and only rent a public one when you have none that can run it. Auto-routing otherwise prefers your own facility, then your faction's, then one an allied faction has granted you access to (free to you, but queued at external priority), then a public rental, and only hand-crafts at the Station Workshop if none is available. Use 'workshop' to force hand-crafting even when you have a facility.",
      },
      quantity: {
        type: 'integer',
        description:
          'Number of output items to make (default 1). Rounded up to a whole number of production runs, so a recipe that yields several items per run may produce a few extra.',
        positionalIndex: 1,
      },
      source: {
        type: 'string',
        description:
          "Where inputs and labor/rental credits are pulled FROM. Same values as deliver_to: 'storage', 'faction', or 'faction:<bucket>'. Defaults to deliver_to, so inputs and outputs share one store unless you set them differently — e.g. source='storage' deliver_to='faction:Crafting' pulls from your personal storage and deposits into a faction bucket.",
      },
      target: {
        type: 'string',
        description:
          'For package recipes: output destination (storage, cargo, faction, or faction:<bucket>); defaults to source. deliver_to is accepted as an alias.',
      },
    },
  },
